/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`localhost`*/ /*!50003 TRIGGER `sprawdz_telefon_klienta` BEFORE INSERT ON `klient` FOR EACH ROW BEGIN
    IF LENGTH(NEW.numer_telefonu) != 9 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Błąd: Numer telefonu musi składać się z dokładnie 9 cyfr!';
    END IF;
END */;;
