CREATE DEFINER=`admin`@`localhost` FUNCTION `f_ilosc_dostepnych_sztuk_wariantu`(p_wariant_id INT) RETURNS int
    DETERMINISTIC
BEGIN
	DECLARE ilosc INT;
	SET ilosc = 0;

    SELECT COUNT(*) INTO ilosc
	FROM wariant w
    JOIN egzemplarz e ON e.wariant_id = p_wariant_id
    WHERE w.wariant_id = e.wariant_id
		AND e.status = 'na_stanie';

    RETURN ilosc ;
END ;;
