CREATE DEFINER=`admin`@`localhost` FUNCTION `f_suma_wydatkow_konta`(
    p_konto_id INT
) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN
    DECLARE v_suma DECIMAL(10,2);

    SELECT ROUND(SUM(z_w.ilosc * z_w.cena), 2)
    INTO v_suma
    FROM ((((`klient` kl
        LEFT JOIN `konto` ko ON kl.konto_id = ko.konto_id)
        LEFT JOIN `zamowienie` za ON kl.konto_id = za.konto_id)
        LEFT JOIN `zamowienie_wariant` z_w ON za.zamowienie_id = z_w.zamowienie_id)
        LEFT JOIN `zamowienie_egzemplarz` z_e ON za.zamowienie_id = z_e.zamowienie_id)
    WHERE ko.konto_id = p_konto_id
      AND za.status <> 'anulowane'
      AND z_e.zwrot_id IS NULL;

    RETURN v_suma;
END ;;
DELIMITER ;
