CREATE DEFINER=`admin`@`localhost` FUNCTION `f_wartosc_koszyka`(
    p_koszyk_id INT
) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN
    DECLARE v_wartosc DECIMAL(10,2);

    SELECT ROUND(SUM(w_k.ilosc * wa.cena), 2)
    INTO v_wartosc
    FROM wariant_koszyk w_k
    JOIN wariant wa ON wa.wariant_id = w_k.wariant_id
    WHERE w_k.koszyk_id = p_koszyk_id;

    RETURN v_wartosc;
END ;;
DELIMITER ;
