CREATE DEFINER=`admin`@`localhost` FUNCTION `f_wartosc_zamowienia`(
    p_zamowienie_id INT
) RETURNS decimal(10,2)
    DETERMINISTIC
BEGIN

	DECLARE v_wartosc DECIMAL(10,2);
    SELECT SUM(p.kwota)
    INTO v_wartosc
    FROM platnosci p
    WHERE p.zamowienie_id = p_zamowienie_id;

    RETURN v_wartosc;
END ;;
