/*!50001 VIEW `v_klienci_z_wydatkami_powyzej_sredniej` AS with `wydatki` as (select `klient`.`klient_id` AS `klient_id`,`klient`.`imie` AS `imie`,`klient`.`nazwisko` AS `nazwisko`,`klient`.`email` AS `email`,sum((`z_w`.`ilosc` * `z_w`.`cena`)) AS `suma_wydatkow` from (((`klient` join `konto` on((`klient`.`konto_id` = `konto`.`konto_id`))) join `zamowienie` `za1` on((`klient`.`konto_id` = `za1`.`konto_id`))) join `zamowienie_wariant` `z_w` on((`za1`.`zamowienie_id` = `z_w`.`zamowienie_id`))) where ((`za1`.`status` = 'zrealizowane') and exists(select 1 from `zamowienie_egzemplarz` `z_e` where ((`z_e`.`zamowienie_id` = `za1`.`zamowienie_id`) and (`z_e`.`zwrot_id` is not null))) is false) group by `klient`.`klient_id`,`klient`.`imie`,`klient`.`nazwisko`,`klient`.`email`), `srednia` as (select avg(`wydatki`.`suma_wydatkow`) AS `avg_wydatkow` from `wydatki`) select `wydatki`.`klient_id` AS `klient_id`,`wydatki`.`imie` AS `imie`,`wydatki`.`nazwisko` AS `nazwisko`,`wydatki`.`email` AS `email`,round(`wydatki`.`suma_wydatkow`,2) AS `suma_wydatkow` from `wydatki` where (`wydatki`.`suma_wydatkow` > (select `srednia`.`avg_wydatkow` from `srednia`)) order by `wydatki`.`suma_wydatkow` desc */;
